if (expand != null) {
queryParameters['expand'] = expand.join(',');
}

final headers = <String, String>{..._config.defaultHeaders};

final request = ApiRequest(
  method: 'GET',
  path: '/v1/account',
  headers: headers,
  queryParameters: queryParameters,
  queryParametersList: queryParametersList,
);

